checker_dsl:
EXISTS (`variable access VA`) {  
  AND {
    EXISTS (`SSA source variable V`, `string MSG`, `expression REASON`) {  
      EXISTS (`SSA definition ORIGIN`, `SSA definition SSA`, `control flow node SRC`, `control flow node SINK`) {  
        AND {  
          (`NullnessFlow::flow(SRC, ORIGIN, SINK, SSA)`),  
          (`SSA.getSourceVariable() = V`),  
          (`varDereference(SSA, VA) = SINK`),  
          OR {  
            EXISTS (`expression E`) {  
              AND {  
                (`REASON = E`),  
                (`guardSuggestsVarMaybeNull(E, ORIGIN)`),  
                (`SRC = ORIGIN.getControlFlowNode()`),  
                (`ORIGIN is not an instance of SsaPhiDefinition`),  
                (`clearlyNotNull(ORIGIN) is false`),  
                NOT {  
                  EXISTS (`try statement TRY`) {  
                    (`TRY.getFinally() = E.getEnclosingStmt().getEnclosingStmt*()`)  
                  }  
                },  
                OR {  
                  EXISTS (`conditional expression C`) {  
                    (`E = C.getCondition().getAChildExpr*()`)  
                  },  
                  NOT {  
                    EXISTS (`method call MA`) {  
                      (`MA.getAnArgument().getAChildExpr*() = E`)  
                    }  
                  }  
                },  
                NOT {  
                  EXISTS (`variable assignment ASSIGN`) {  
                    AND {  
                      (`ORIGIN is an instance of SsaExplicitWrite`),  
                      (`ORIGIN.getDefiningExpr() = ASSIGN`),  
                      (`ASSIGN.getSource() = nullExpr()`)  
                    }  
                  }  
                }  
              }  
            },  
            EXISTS (`parameter P`, `expression ARG`) {  
              AND {  
                (`ORIGIN is an instance of SsaParameterInit`),  
                (`ORIGIN.getParameter() = P`),  
                (`SRC = ORIGIN.getControlFlowNode()`),  
                (`P.getAnArgument() = ARG`),  
                (`REASON = ARG`),  
                (`ARG is a null expression`),  
                NOT {  
                  EXISTS (`callable CALLABLE`) {  
                    AND {  
                      (`ARG.getEnclosingCallable().getEnclosingCallable*() = CALLABLE`),  
                      (`CALLABLE is an instance of TestMethod`)  
                    }  
                  }  
                }  
              }  
            },  
            EXISTS (`variable assignment DEF`) {  
              AND {  
                (`ORIGIN is an instance of SsaExplicitWrite`),  
                (`ORIGIN.getDefiningExpr() = DEF`),  
                (`DEF.getSource() = nullExpr(SRC.asExpr())`),  
                (`REASON = DEF`)  
              }  
            }  
          }  
        }  
      }
    },
    NOT {  
      EXISTS (`basic block BB`, `SSA definition SSA2`) {  
        AND {  
          (`V.getVariable() is not an instance of Field`),  
          (`firstVarDereferenceInBlock(BB, SSA2, VA)`),  
          (`SSA2.getSourceVariable() = V`),  
          (`nullGuardControls(SSA2, false, BB) is false`),  
          OR {  
            FORALL (`SSA definition DEF2`) {  
              AND {  
                (`DEF2 = SSA2.getAnUltimateDefinition()`),  
                (`DEF2 is an instance of SsaExplicitWrite`),  
                (`DEF2.getValue() = alwaysNullExpr()`)  
              }  
            },  
            AND {  
              (`nullGuardControls(SSA2, true, BB)`),  
              (`clearlyNotNull(SSA2) is false`)  
            }  
          }  
        }  
      }  
    }
  }
}
